    const n = countLiveNeighbors(x, y, liveSet);
    const alive = liveSet.has(k);
    // Conway's rule: alive next gen iff exactly 3 neighbors, or alive with 2.
    if (n === 3 || (alive && n === 2)) {
      next.push([x, y]);
    }
  }
  return next;
};
